		vcexecutequery
		<Описание>Выполняет в базе запрос на языке 1С, передаваемый в параметре [ТекстЗапроса] и возвращает результат в текстовом виде. Все параметры запроса должны быть заданы непосредственно в тексте запроса. Запрос должен быть или в одну строку или перенос строк через символ "|" (вертикальная черта) - по правилам 1С. Если задаются параметры нужно не забывать экранировать кавычки.</Описание>
		<ЗапросКод>Результат = "пустой";
Запрос = Новый Запрос;
	Запрос.Текст = ТекстЗапроса;

	РезультатЗапроса = Запрос.Выполнить();
	ТаблицаРезультата = РезультатЗапроса.Выгрузить();

	Разделитель = " | ";

	ЧастиЗаголовка = Новый Массив;
	Для Каждого Колонка Из ТаблицаРезультата.Колонки Цикл

		ЧастиЗаголовка.Добавить(Колонка.Имя);

	КонецЦикла;

	Результат = СтрСоединить(ЧастиЗаголовка, Разделитель);

	Для Каждого СтрокаТаблицы Из ТаблицаРезультата Цикл

		ЧастиСтроки = Новый Массив;

		Для Каждого Колонка Из ТаблицаРезультата.Колонки Цикл

			Значение = СтрокаТаблицы[Колонка.Имя];
			ЧастиСтроки.Добавить(Строка(Значение));

		КонецЦикла;

		Результат = Результат + Символы.ПС + СтрСоединить(ЧастиСтроки, Разделитель);

	КонецЦикла;
</ЗапросКод>
		<ВариантОтчета>00000000-0000-0000-0000-000000000000</ВариантОтчета>
		<Параметры>
			<Имя>ТекстЗапроса</Имя>
			<ИмяEn>querytext</ИмяEn>
			<Описание>Текст запроса на языке 1С</Описание>
		</Параметры>
